const settings = {};

for (const item of $input.all()) {
  const row = item.json;

  const key = String(
    row.key ||
    row.setting ||
    row.name ||
    ""
  ).trim();

  if (!key) continue;

  settings[key] =
    row.value ??
    row.setting_value ??
    "";
}

return [
  {
    json: {
      settings: {
        workName:
          settings.work_name || "Работа",

        workLatitude:
          Number(settings.work_latitude),

        workLongitude:
          Number(settings.work_longitude),

        departureTime:
          String(settings.departure_time || "23:00"),

        maxPassengers:
          Math.max(
            1,
            Number(settings.max_passengers || 3)
          ),

        reportChatId:
          String(settings.report_chat_id || "")
      }
    }
  }
];

const {
  passengers,
  settings,
  carNumber,
  totalCars,
  totalEmployees
} = $json;

if (!Array.isArray(passengers) || passengers.length === 0) {
  throw new Error(`У машины №${carNumber} нет пассажиров`);
}

const workLatitude = Number(settings.workLatitude);
const workLongitude = Number(settings.workLongitude);

function straightDistance(employee) {
  const latDiff =
    Number(employee.latitude) - workLatitude;

  const lngDiff =
    Number(employee.longitude) - workLongitude;

  return Math.sqrt(
    latDiff * latDiff +
    lngDiff * lngDiff
  );
}

/*
  Самого дальнего пассажира делаем конечной точкой.
  Это снижает риск, что машина сначала уедет далеко,
  а потом вернётся назад к последнему адресу.
*/
const sortedPassengers = [...passengers].sort(
  (a, b) =>
    straightDistance(a) - straightDistance(b)
);

const destinationPassenger =
  sortedPassengers[sortedPassengers.length - 1];

const intermediatePassengers =
  sortedPassengers.slice(0, -1);

const routeRequestBody = {
  origin: {
    location: {
      latLng: {
        latitude: workLatitude,
        longitude: workLongitude
      }
    }
  },

  destination: {
    location: {
      latLng: {
        latitude: Number(destinationPassenger.latitude),
        longitude: Number(destinationPassenger.longitude)
      }
    }
  },

  travelMode: "DRIVE",
  routingPreference: "TRAFFIC_AWARE",
  computeAlternativeRoutes: false,
  languageCode: "ru",
  units: "METRIC"
};

if (intermediatePassengers.length > 0) {
  routeRequestBody.intermediates =
    intermediatePassengers.map(employee => ({
      location: {
        latLng: {
          latitude: Number(employee.latitude),
          longitude: Number(employee.longitude)
        }
      }
    }));

  routeRequestBody.optimizeWaypointOrder = true;
}

return {
  carNumber,
  totalCars,
  totalEmployees,

  passengerCount: passengers.length,
  passengers,

  intermediatePassengers,
  destinationPassenger,

  settings,
  routeRequestBody
};

const sources = $("Prepare Route Request").all();
const source = sources[$itemIndex]?.json;

if (!source) {
  throw new Error(
    `Не найдены данные маршрута для item ${$itemIndex}`
  );
}

const route = $json.routes?.[0];

if (!route) {
  throw new Error(
    `Google Routes не вернул маршрут для машины №${source.carNumber}`
  );
}

const distanceMeters =
  Number(route.distanceMeters || 0);

const durationSeconds =
  Number(
    String(route.duration || "0s")
      .replace("s", "")
  );

const distanceKm =
  Math.round((distanceMeters / 1000) * 10) / 10;

const durationMinutes =
  Math.ceil(durationSeconds / 60);

const intermediatePassengers =
  Array.isArray(source.intermediatePassengers)
    ? source.intermediatePassengers.filter(Boolean)
    : [];

const destinationPassenger =
  source.destinationPassenger;

if (!destinationPassenger) {
  throw new Error(
    `Не найдена конечная точка машины №${source.carNumber}`
  );
}

const optimizedIndexes =
  Array.isArray(
    route.optimizedIntermediateWaypointIndex
  )
    ? route.optimizedIntermediateWaypointIndex
    : [];

/*
  Google возвращает список исходных индексов
  в новом оптимизированном порядке.

  Например [2, 0, 1] означает:
  сначала intermediate[2],
  потом intermediate[0],
  потом intermediate[1].
*/
let optimizedIntermediates =
  [...intermediatePassengers];

if (
  optimizedIndexes.length ===
  intermediatePassengers.length
) {
  const candidateOrder =
    optimizedIndexes.map(index =>
      intermediatePassengers[Number(index)]
    );

  if (
    candidateOrder.length ===
      intermediatePassengers.length &&
    candidateOrder.every(Boolean)
  ) {
    optimizedIntermediates = candidateOrder;
  }
}

const orderedPassengers = [
  ...optimizedIntermediates,
  destinationPassenger
];

/*
  Проверяем, что никто не пропал.
*/
if (
  orderedPassengers.length !==
  Number(source.passengerCount)
) {
  throw new Error(
    `Машина №${source.carNumber}: ` +
    `было ${source.passengerCount} пассажиров, ` +
    `после оптимизации осталось ${orderedPassengers.length}`
  );
}

const workLatitude =
  Number(source.settings.workLatitude);

const workLongitude =
  Number(source.settings.workLongitude);

const routePoints = orderedPassengers
  .map(passenger =>
    `${Number(passenger.latitude)},` +
    `${Number(passenger.longitude)}`
  )
  .join("/");

const googleMapsUrl =
  `https://www.google.com/maps/dir/` +
  `${workLatitude},${workLongitude}/` +
  routePoints;

const now = new Date();

const routeDate =
  new Intl.DateTimeFormat("en-CA", {
    timeZone: "Europe/Kyiv",
    year: "numeric",
    month: "2-digit",
    day: "2-digit"
  }).format(now);

return {
  carNumber: source.carNumber,
  totalCars: source.totalCars,
  totalEmployees: source.totalEmployees,

  passengerCount: orderedPassengers.length,
  passengers: orderedPassengers,

  distanceMeters,
  distanceKm,
  durationSeconds,
  durationMinutes,

  departureTime:
    source.settings.departureTime,

  workName:
    source.settings.workName,

  reportChatId:
    source.settings.reportChatId,

  googleMapsUrl,
  routeDate,

  createdAt: now.toLocaleString("sv-SE", {
    timeZone: "Europe/Kyiv"
  })
};

const today = new Intl.DateTimeFormat("en-CA", {
  timeZone: "Europe/Kyiv",
  year: "numeric",
  month: "2-digit",
  day: "2-digit"
}).format(new Date());

const rows = $input.all()
  .map(item => item.json);

const employees = rows.filter(row => {
  const active =
    String(row.active || "")
      .trim()
      .toUpperCase() === "TRUE";

  const registered =
    String(row.registration_status || "")
      .trim()
      .toLowerCase() === "completed";

  const needsTaxi =
    String(row.needs_taxi || "")
      .trim()
      .toUpperCase() === "TRUE";

  const taxiDate =
    String(row.taxi_date || "")
      .trim();

  const latitude = Number(row.latitude);
  const longitude = Number(row.longitude);

  const hasCoordinates =
    Number.isFinite(latitude) &&
    Number.isFinite(longitude);

  return (
    active &&
    registered &&
    needsTaxi &&
    taxiDate === today &&
    hasCoordinates
  );
});

return employees.map(employee => ({
  json: {
    ...employee,
    latitude: Number(employee.latitude),
    longitude: Number(employee.longitude)
  }
}));

const passengerNames =
  $json.passengers
    .map(employee => employee.name)
    .join(", ");

const passengerAddresses =
  $json.passengers
    .map(employee => employee.address)
    .join(" → ");

return {
  route_date: $json.routeDate,
  departure_time: $json.departureTime,

  car_number: $json.carNumber,
  total_cars: $json.totalCars,

  passenger_count: $json.passengerCount,
  passengers: passengerNames,
  addresses: passengerAddresses,

  distance_km: $json.distanceKm,
  duration_minutes: $json.durationMinutes,

  google_maps_url: $json.googleMapsUrl,
  created_at: $json.createdAt
};

const routes = $input.all()
  .map(item => item.json)
  .sort(
    (a, b) => a.carNumber - b.carNumber
  );

if (
  routes.length === 1 &&
  routes[0].noEmployees
) {
  return [
    {
      json: {
        chatId:
          routes[0].settings?.reportChatId || "",

        message:
          "🚖 Сегодня никто не отметил необходимость развозки."
      }
    }
  ];
}

const totalCars = routes.length;

const totalEmployees =
  routes.reduce(
    (sum, route) =>
      sum + route.passengerCount,
    0
  );

const totalDistanceKm =
  Math.round(
    routes.reduce(
      (sum, route) =>
        sum + route.distanceKm,
      0
    ) * 10
  ) / 10;

const totalDurationMinutes =
  routes.reduce(
    (sum, route) =>
      sum + route.durationMinutes,
    0
  );

const date = routes[0].routeDate;
const departureTime =
  routes[0].departureTime;

const routeSections = routes.map(route => {
  const passengers = route.passengers
    .map(
      (employee, index) =>
        `${index + 1}. ${employee.name}` +
        `${employee.address ? ` — ${employee.address}` : ""}`
    )
    .join("\n");

  return [
    `🚕 Машина №${route.carNumber}`,
    `Пассажиров: ${route.passengerCount}`,
    "",
    passengers,
    "",
    `📏 Расстояние: ${route.distanceKm} км`,
    `⏱ Время в пути: около ${route.durationMinutes} мин`,
    `🗺 Маршрут: ${route.googleMapsUrl}`
  ].join("\n");
});

const message = [
  `🚖 Развозка на ${date}`,
  "",
  `🕚 Время выезда: ${departureTime}`,
  `👥 Сотрудников: ${totalEmployees}`,
  `🚕 Необходимо машин: ${totalCars}`,
  `📏 Общее расстояние: ${totalDistanceKm} км`,
  `⏱ Суммарное время маршрутов: около ${totalDurationMinutes} мин`,
  "",
  routeSections.join("\n\n────────────\n\n")
].join("\n");

return [
  {
    json: {
      chatId: routes[0].reportChatId,
      totalCars,
      totalEmployees,
      totalDistanceKm,
      totalDurationMinutes,
      message
    }
  }
];

const items = $input.all();

if (items.length === 0) {
  return [
    {
      json: {
        noEmployees: true,
        totalEmployees: 0,
        totalCars: 0
      }
    }
  ];
}

const settings = items[0].json.settings;

const employees = items.map((item, index) => ({
  index,
  telegramUserId: String(item.json.telegramUserId || ""),
  telegramUsername: item.json.telegramUsername || "",
  name: item.json.name || "Без имени",
  address: item.json.address || "",
  latitude: Number(item.json.latitude),
  longitude: Number(item.json.longitude),
  area: item.json.area || ""
}));

for (const employee of employees) {
  if (
    !Number.isFinite(employee.latitude) ||
    !Number.isFinite(employee.longitude)
  ) {
    throw new Error(
      `Некорректные координаты у сотрудника: ${employee.name}`
    );
  }
}

/*
  Добавляем работу как точку 0.
  Сотрудники начинаются с индекса 1.
*/
const locations = [
  {
    type: "work",
    name: settings.workName || "Работа",
    latitude: Number(settings.workLatitude),
    longitude: Number(settings.workLongitude)
  },
  ...employees.map(employee => ({
    type: "employee",
    name: employee.name,
    latitude: employee.latitude,
    longitude: employee.longitude
  }))
];

const origins = locations.map(location => ({
  waypoint: {
    location: {
      latLng: {
        latitude: location.latitude,
        longitude: location.longitude
      }
    }
  }
}));

const destinations = locations.map(location => ({
  waypoint: {
    location: {
      latLng: {
        latitude: location.latitude,
        longitude: location.longitude
      }
    }
  }
}));

return [
  {
    json: {
      employees,
      settings,
      locations,

      matrixRequestBody: {
        origins,
        destinations,
        travelMode: "DRIVE",
        routingPreference: "TRAFFIC_AWARE"
      }
    }
  }
];

const matrixItems = $input.all().map(item => item.json);
const source = $("Prepare Route Matrix").first().json;

if (source.noEmployees) {
  return [{ json: source }];
}

const settings = source.settings || {};

const maxPassengers = Math.max(
  1,
  Math.floor(Number(settings.maxPassengers || 4))
);

const employees = Array.isArray(source.employees)
  ? source.employees.map((employee, position) => ({
      ...employee,

      /*
        Уникальная внутренняя позиция сотрудника.
        Она используется только внутри алгоритма.
      */
      __position: position,

      /*
        Индекс сотрудника в Route Matrix.

        Индекс 0 в матрице — место работы.
        Поэтому первый сотрудник обычно имеет индекс 1.
      */
      __matrixIndex:
        Number.isInteger(Number(employee.index))
          ? Number(employee.index) + 1
          : position + 1
    }))
  : [];

const employeeCount = employees.length;

if (employeeCount === 0) {
  return [
    {
      json: {
        noEmployees: true,
        totalEmployees: 0,
        totalCars: 0,
        settings
      }
    }
  ];
}

const totalCars = Math.ceil(
  employeeCount / maxPassengers
);

const locationCount = employeeCount + 1;

/*
  Настройки алгоритма.

  До 10 сотрудников:
  точный перебор всех допустимых распределений.

  От 11 сотрудников:
  быстрая многопроходная оптимизация.
*/
const EXACT_OPTIMIZATION_LIMIT = 10;

const HEURISTIC_RESTARTS = Math.min(
  30,
  Math.max(10, employeeCount * 2)
);

const LOCAL_SEARCH_MAX_ITERATIONS = 100;

const EPSILON = 0.001;

/*
  Матрица расстояний.

  Индекс 0 — место работы.
  Индексы 1...N — сотрудники.
*/
const distances = Array.from(
  { length: locationCount },
  () => Array(locationCount).fill(Infinity)
);

for (let i = 0; i < locationCount; i++) {
  distances[i][i] = 0;
}

/*
  Заполняем матрицу результатами Google Route Matrix.
*/
for (const element of matrixItems) {
  const originIndex = Number(element.originIndex);

  const destinationIndex = Number(
    element.destinationIndex
  );

  const distanceMeters = Number(
    element.distanceMeters
  );

  if (
    Number.isInteger(originIndex) &&
    Number.isInteger(destinationIndex) &&
    originIndex >= 0 &&
    destinationIndex >= 0 &&
    originIndex < locationCount &&
    destinationIndex < locationCount &&
    Number.isFinite(distanceMeters)
  ) {
    distances[originIndex][destinationIndex] =
      distanceMeters;
  }
}

/*
  Удаляем технические поля перед передачей
  сотрудников в следующие узлы.
*/
function cleanEmployee(employee) {
  const result = { ...employee };

  delete result.__position;
  delete result.__matrixIndex;

  return result;
}

function matrixIndexByPosition(position) {
  const employee = employees[position];

  if (!employee) {
    return null;
  }

  return employee.__matrixIndex;
}

/*
  Получение расстояния между двумя точками.

  fromPosition === -1 означает место работы.
  toPosition === -1 означает место работы.
*/
function distanceBetweenPositions(
  fromPosition,
  toPosition
) {
  const fromIndex =
    fromPosition === -1
      ? 0
      : matrixIndexByPosition(fromPosition);

  const toIndex =
    toPosition === -1
      ? 0
      : matrixIndexByPosition(toPosition);

  if (
    fromIndex === null ||
    toIndex === null ||
    fromIndex === undefined ||
    toIndex === undefined
  ) {
    return Infinity;
  }

  const direct =
    distances[fromIndex]?.[toIndex];

  if (Number.isFinite(direct)) {
    return direct;
  }

  /*
    Запасной вариант:
    если прямого направления нет,
    используем обратное расстояние.
  */
  const reverse =
    distances[toIndex]?.[fromIndex];

  if (Number.isFinite(reverse)) {
    return reverse;
  }

  return Infinity;
}

function workDistance(position) {
  return distanceBetweenPositions(
    -1,
    position
  );
}

/*
  Среднее расстояние между двумя сотрудниками.

  Используется только для формирования
  начальных групп в эвристическом режиме.
*/
function pairDistance(
  positionA,
  positionB
) {
  const forward =
    distanceBetweenPositions(
      positionA,
      positionB
    );

  const backward =
    distanceBetweenPositions(
      positionB,
      positionA
    );

  if (
    Number.isFinite(forward) &&
    Number.isFinite(backward)
  ) {
    return (forward + backward) / 2;
  }

  if (Number.isFinite(forward)) {
    return forward;
  }

  if (Number.isFinite(backward)) {
    return backward;
  }

  return Infinity;
}

/*
  Генератор всех вариантов порядка пассажиров.

  При вместимости машины 4 человека:
  максимум 4! = 24 варианта.
*/
function generatePermutations(values) {
  if (values.length <= 1) {
    return [values.slice()];
  }

  const result = [];

  for (let i = 0; i < values.length; i++) {
    const current = values[i];

    const remaining = [
      ...values.slice(0, i),
      ...values.slice(i + 1)
    ];

    const tails =
      generatePermutations(remaining);

    for (const tail of tails) {
      result.push([
        current,
        ...tail
      ]);
    }
  }

  return result;
}

/*
  Считаем длину маршрута:

  Работа
  → пассажир 1
  → пассажир 2
  → пассажир 3
  → пассажир 4

  Возврат машины на работу не учитывается.
*/
function routeDistance(order) {
  if (
    !Array.isArray(order) ||
    order.length === 0
  ) {
    return 0;
  }

  let total = 0;
  let previousPosition = -1;

  for (const position of order) {
    const segment =
      distanceBetweenPositions(
        previousPosition,
        position
      );

    if (!Number.isFinite(segment)) {
      return Infinity;
    }

    total += segment;
    previousPosition = position;
  }

  return total;
}

/*
  Кэш оптимального порядка пассажиров
  для каждой группы.
*/
const routeCache = new Map();

function groupCacheKey(group) {
  return [...group]
    .sort((a, b) => a - b)
    .join(",");
}

function getBestRoute(group) {
  const normalized = [...group]
    .sort((a, b) => a - b);

  const key = groupCacheKey(normalized);

  if (routeCache.has(key)) {
    return routeCache.get(key);
  }

  if (
    normalized.length === 0 ||
    normalized.length > maxPassengers
  ) {
    const invalid = {
      distance: Infinity,
      order: []
    };

    routeCache.set(key, invalid);

    return invalid;
  }

  let bestDistance = Infinity;
  let bestOrder = null;

  const permutations =
    generatePermutations(normalized);

  for (const order of permutations) {
    const currentDistance =
      routeDistance(order);

    if (currentDistance < bestDistance) {
      bestDistance = currentDistance;
      bestOrder = order;
    }
  }

  const result = {
    distance: bestDistance,
    order: bestOrder || normalized
  };

  routeCache.set(key, result);

  return result;
}

/*
  Общая длина маршрутов всех машин.
*/
function solutionDistance(groups) {
  let total = 0;

  for (const group of groups) {
    const route = getBestRoute(group);

    if (!Number.isFinite(route.distance)) {
      return Infinity;
    }

    total += route.distance;
  }

  return total;
}

/*
  ==================================================
  ТОЧНАЯ ОПТИМИЗАЦИЯ ДЛЯ 1–10 СОТРУДНИКОВ
  ==================================================
*/

function countBits(mask) {
  let count = 0;
  let value = mask;

  while (value > 0) {
    count += value & 1;
    value >>>= 1;
  }

  return count;
}

function firstSetBit(mask) {
  for (let i = 0; i < employeeCount; i++) {
    if (mask & (1 << i)) {
      return i;
    }
  }

  return -1;
}

function positionsFromMask(mask) {
  const result = [];

  for (let i = 0; i < employeeCount; i++) {
    if (mask & (1 << i)) {
      result.push(i);
    }
  }

  return result;
}

/*
  Генерируем допустимые составы одной машины.

  anchor обязательно входит в группу.
  Это предотвращает повторную проверку
  одинаковых перестановок машин.
*/
function generateGroupMasks(
  remainingMask,
  anchor,
  minSize,
  maxSize
) {
  const available = [];

  for (let i = 0; i < employeeCount; i++) {
    if (
      i !== anchor &&
      (remainingMask & (1 << i))
    ) {
      available.push(i);
    }
  }

  const result = [];
  const anchorMask = 1 << anchor;

  function build(
    startIndex,
    needed,
    currentMask
  ) {
    if (needed === 0) {
      result.push(
        currentMask | anchorMask
      );

      return;
    }

    for (
      let i = startIndex;
      i <= available.length - needed;
      i++
    ) {
      build(
        i + 1,
        needed - 1,
        currentMask | (1 << available[i])
      );
    }
  }

  for (
    let size = minSize;
    size <= maxSize;
    size++
  ) {
    build(
      0,
      size - 1,
      0
    );
  }

  return result;
}

function exactOptimization() {
  const memo = new Map();

  function solve(
    remainingMask,
    carsLeft
  ) {
    const memoKey =
      `${remainingMask}:${carsLeft}`;

    if (memo.has(memoKey)) {
      return memo.get(memoKey);
    }

    const remainingCount =
      countBits(remainingMask);

    if (remainingCount === 0) {
      const result =
        carsLeft === 0
          ? {
              distance: 0,
              groups: []
            }
          : null;

      memo.set(memoKey, result);

      return result;
    }

    if (carsLeft <= 0) {
      memo.set(memoKey, null);

      return null;
    }

    /*
      Проверяем, можно ли разместить
      оставшихся сотрудников.
    */
    if (
      remainingCount < carsLeft ||
      remainingCount >
        carsLeft * maxPassengers
    ) {
      memo.set(memoKey, null);

      return null;
    }

    const anchor =
      firstSetBit(remainingMask);

    const minGroupSize = Math.max(
      1,
      remainingCount -
        (carsLeft - 1) * maxPassengers
    );

    const maxGroupSize = Math.min(
      maxPassengers,
      remainingCount -
        (carsLeft - 1)
    );

    const groupMasks =
      generateGroupMasks(
        remainingMask,
        anchor,
        minGroupSize,
        maxGroupSize
      );

    let best = null;

    for (const groupMask of groupMasks) {
      const group =
        positionsFromMask(groupMask);

      const route =
        getBestRoute(group);

      if (!Number.isFinite(route.distance)) {
        continue;
      }

      const nextMask =
        remainingMask & ~groupMask;

      const rest =
        solve(
          nextMask,
          carsLeft - 1
        );

      if (!rest) {
        continue;
      }

      const totalDistance =
        route.distance +
        rest.distance;

      if (
        !best ||
        totalDistance <
          best.distance - EPSILON
      ) {
        best = {
          distance: totalDistance,
          groups: [
            group,
            ...rest.groups
          ]
        };
      }
    }

    memo.set(memoKey, best);

    return best;
  }

  const fullMask =
    (1 << employeeCount) - 1;

  const result =
    solve(
      fullMask,
      totalCars
    );

  if (!result) {
    throw new Error(
      "Не удалось выполнить точную оптимизацию маршрутов"
    );
  }

  return {
    groups: result.groups,
    distance: result.distance,
    method: "exact_minimum_distance"
  };
}

