  ЭВРИСТИКА ДЛЯ 11 И БОЛЕЕ СОТРУДНИКОВ
  ==================================================
*/

/*
  Детерминированное перемешивание.

  Даёт разные стартовые варианты,
  но результат остаётся воспроизводимым.
*/
function seededShuffle(
  values,
  seed
) {
  const result = [...values];

  let state =
    (seed + 1) * 2654435761;

  function random() {
    state ^= state << 13;
    state ^= state >>> 17;
    state ^= state << 5;

    return (
      (state >>> 0) /
      4294967296
    );
  }

  for (
    let i = result.length - 1;
    i > 0;
    i--
  ) {
    const j = Math.floor(
      random() * (i + 1)
    );

    [result[i], result[j]] =
      [result[j], result[i]];
  }

  return result;
}

/*
  Выбираем стартовые точки машин так,
  чтобы они находились в разных направлениях.
*/
function selectAnchors(seed) {
  const allPositions =
    Array.from(
      { length: employeeCount },
      (_, index) => index
    );

  let candidates;

  if (seed === 0) {
    candidates = [...allPositions].sort(
      (a, b) =>
        workDistance(b) -
        workDistance(a)
    );
  } else {
    candidates =
      seededShuffle(
        allPositions,
        seed
      );
  }

  const anchors = [];

  if (candidates.length > 0) {
    anchors.push(candidates[0]);
  }

  while (
    anchors.length < totalCars
  ) {
    let bestCandidate = null;
    let bestScore = -Infinity;

    for (const candidate of allPositions) {
      if (anchors.includes(candidate)) {
        continue;
      }

      let minAnchorDistance = Infinity;

      for (const anchor of anchors) {
        minAnchorDistance = Math.min(
          minAnchorDistance,
          pairDistance(
            candidate,
            anchor
          )
        );
      }

      const score =
        minAnchorDistance +
        workDistance(candidate) * 0.15;

      if (score > bestScore) {
        bestScore = score;
        bestCandidate = candidate;
      }
    }

    if (bestCandidate === null) {
      break;
    }

    anchors.push(bestCandidate);
  }

  return anchors;
}

/*
  Создаём начальное распределение.
*/
function buildInitialGroups(seed) {
  const anchors =
    selectAnchors(seed);

  const groups =
    anchors.map(anchor => [anchor]);

  const assigned =
    new Set(anchors);

  let remaining =
    Array.from(
      { length: employeeCount },
      (_, index) => index
    ).filter(
      position =>
        !assigned.has(position)
    );

  if (seed > 0) {
    remaining =
      seededShuffle(
        remaining,
        seed * 17 + 3
      );
  } else {
    remaining.sort(
      (a, b) =>
        workDistance(b) -
        workDistance(a)
    );
  }

  while (remaining.length > 0) {
    let bestMove = null;

    for (
      let candidateIndex = 0;
      candidateIndex < remaining.length;
      candidateIndex++
    ) {
      const candidate =
        remaining[candidateIndex];

      for (
        let groupIndex = 0;
        groupIndex < groups.length;
        groupIndex++
      ) {
        const group =
          groups[groupIndex];

        if (
          group.length >= maxPassengers
        ) {
          continue;
        }

        const currentDistance =
          getBestRoute(group).distance;

        const nextDistance =
          getBestRoute([
            ...group,
            candidate
          ]).distance;

        if (
          !Number.isFinite(nextDistance)
        ) {
          continue;
        }

        const increase =
          nextDistance -
          currentDistance;

        /*
          Небольшой штраф за слишком раннее
          заполнение одной машины.
        */
        const balancePenalty =
          group.length * 25;

        const score =
          increase +
          balancePenalty;

        if (
          !bestMove ||
          score < bestMove.score
        ) {
          bestMove = {
            candidateIndex,
            candidate,
            groupIndex,
            score
          };
        }
      }
    }

    if (!bestMove) {
      throw new Error(
        "Не удалось создать начальные группы. Проверьте Route Matrix."
      );
    }

    groups[bestMove.groupIndex].push(
      bestMove.candidate
    );

    remaining.splice(
      bestMove.candidateIndex,
      1
    );
  }

  return groups;
}

/*
  Ищем выгодный перенос одного сотрудника
  из одной машины в другую.
*/
function findBestRelocation(groups) {
  let bestMove = null;

  const currentTotal =
    solutionDistance(groups);

  for (
    let fromGroupIndex = 0;
    fromGroupIndex < groups.length;
    fromGroupIndex++
  ) {
    const fromGroup =
      groups[fromGroupIndex];

    /*
      Не оставляем пустую машину.
    */
    if (fromGroup.length <= 1) {
      continue;
    }

    for (
      let passengerIndex = 0;
      passengerIndex < fromGroup.length;
      passengerIndex++
    ) {
      const passenger =
        fromGroup[passengerIndex];

      for (
        let toGroupIndex = 0;
        toGroupIndex < groups.length;
        toGroupIndex++
      ) {
        if (
          fromGroupIndex === toGroupIndex
        ) {
          continue;
        }

        const toGroup =
          groups[toGroupIndex];

        if (
          toGroup.length >= maxPassengers
        ) {
          continue;
        }

        const candidateGroups =
          groups.map(
            group => [...group]
          );

        candidateGroups[fromGroupIndex]
          .splice(passengerIndex, 1);

        candidateGroups[toGroupIndex]
          .push(passenger);

        const candidateTotal =
          solutionDistance(candidateGroups);

        const improvement =
          currentTotal -
          candidateTotal;

        if (
          improvement > EPSILON &&
          (
            !bestMove ||
            improvement >
              bestMove.improvement
          )
        ) {
          bestMove = {
            groups: candidateGroups,
            improvement
          };
        }
      }
    }
  }

  return bestMove;
}

/*
  Ищем выгодный обмен сотрудниками
  между двумя машинами.
*/
function findBestSwap(groups) {
  let bestMove = null;

  const currentTotal =
    solutionDistance(groups);

  for (
    let groupAIndex = 0;
    groupAIndex < groups.length;
    groupAIndex++
  ) {
    for (
      let groupBIndex = groupAIndex + 1;
      groupBIndex < groups.length;
      groupBIndex++
    ) {
      const groupA =
        groups[groupAIndex];

      const groupB =
        groups[groupBIndex];

      for (
        let passengerAIndex = 0;
        passengerAIndex < groupA.length;
        passengerAIndex++
      ) {
        for (
          let passengerBIndex = 0;
          passengerBIndex < groupB.length;
          passengerBIndex++
        ) {
          const candidateGroups =
            groups.map(
              group => [...group]
            );

          const passengerA =
            candidateGroups[groupAIndex][
              passengerAIndex
            ];

          const passengerB =
            candidateGroups[groupBIndex][
              passengerBIndex
            ];

          candidateGroups[groupAIndex][
            passengerAIndex
          ] = passengerB;

          candidateGroups[groupBIndex][
            passengerBIndex
          ] = passengerA;

          const candidateTotal =
            solutionDistance(candidateGroups);

          const improvement =
            currentTotal -
            candidateTotal;

          if (
            improvement > EPSILON &&
            (
              !bestMove ||
              improvement >
                bestMove.improvement
            )
          ) {
            bestMove = {
              groups: candidateGroups,
              improvement
            };
          }
        }
      }
    }
  }

  return bestMove;
}

/*
  Локальное улучшение распределения.
*/
function improveGroups(initialGroups) {
  let groups =
    initialGroups.map(
      group => [...group]
    );

  for (
    let iteration = 0;
    iteration <
      LOCAL_SEARCH_MAX_ITERATIONS;
    iteration++
  ) {
    const relocation =
      findBestRelocation(groups);

    const swap =
      findBestSwap(groups);

    let bestMove = null;

    if (
      relocation &&
      (
        !swap ||
        relocation.improvement >=
          swap.improvement
      )
    ) {
      bestMove = relocation;
    } else if (swap) {
      bestMove = swap;
    }

    if (!bestMove) {
      break;
    }

    groups = bestMove.groups;
  }

  return groups;
}

/*
  Запускаем несколько стартовых вариантов
  и выбираем лучший.
*/
function heuristicOptimization() {
  let bestGroups = null;
  let bestDistance = Infinity;

  for (
    let restart = 0;
    restart < HEURISTIC_RESTARTS;
    restart++
  ) {
    const initialGroups =
      buildInitialGroups(restart);

    const improvedGroups =
      improveGroups(initialGroups);

    const distance =
      solutionDistance(improvedGroups);

    if (
      distance <
      bestDistance - EPSILON
    ) {
      bestDistance = distance;

      bestGroups =
        improvedGroups.map(
          group => [...group]
        );
    }
  }

  if (!bestGroups) {
    throw new Error(
      "Не удалось выполнить эвристическую оптимизацию маршрутов"
    );
  }

  return {
    groups: bestGroups,
    distance: bestDistance,
    method:
      "multi_start_route_optimization"
  };
}

/*
  Автоматически выбираем режим.
*/
const optimization =
  employeeCount <= EXACT_OPTIMIZATION_LIMIT
    ? exactOptimization()
    : heuristicOptimization();

/*
  ==================================================
  ПРОВЕРКА РАСПРЕДЕЛЕНИЯ
  ==================================================

  Проверяем внутренние позиции сотрудников.

  Это исправляет ошибку:
  "сотрудников 12, распределено 12, уникальных 1"

  Проверка больше не зависит от telegram_user_id.
*/
const assignedPositions =
  optimization.groups.flat();

const uniqueAssignedPositions =
  new Set(assignedPositions);

if (
  assignedPositions.length !== employeeCount ||
  uniqueAssignedPositions.size !== employeeCount
) {
  throw new Error(
    `Ошибка распределения: сотрудников ${employeeCount}, ` +
    `распределено ${assignedPositions.length}, ` +
    `уникальных ${uniqueAssignedPositions.size}`
  );
}

/*
  Проверяем допустимость каждой позиции.
*/
for (const position of assignedPositions) {
  if (
    !Number.isInteger(position) ||
    position < 0 ||
    position >= employeeCount
  ) {
    throw new Error(
      `Некорректная позиция сотрудника: ${position}`
    );
  }
}

/*
  Формируем итоговые машины.

  Пассажиры уже расположены
  в оптимальном порядке высадки.
*/
const optimizedCars =
  optimization.groups.map(group => {
    if (group.length > maxPassengers) {
      throw new Error(
        `Превышена вместимость машины: ` +
        `${group.length} пассажиров, максимум ${maxPassengers}`
      );
    }

    const bestRoute =
      getBestRoute(group);

    if (
      !Number.isFinite(
        bestRoute.distance
      )
    ) {
      throw new Error(
        `Не удалось рассчитать маршрут для группы: ${group.join(", ")}`
      );
    }

    return {
      positions: bestRoute.order,

      passengers:
        bestRoute.order.map(
          position =>
            cleanEmployee(
              employees[position]
            )
        ),

      distanceMeters:
        bestRoute.distance
    };
  });

/*
  Сначала показываем наиболее длинный маршрут.
  На общий километраж это не влияет.
*/
optimizedCars.sort(
  (a, b) =>
    b.distanceMeters -
    a.distanceMeters
);

const totalOptimizedDistance =
  optimizedCars.reduce(
    (sum, car) =>
      sum + car.distanceMeters,
    0
  );

/*
  Возвращаем по одному item на каждую машину.
*/
return optimizedCars.map(
  (car, index) => ({
    json: {
      carNumber: index + 1,

      totalCars:
        optimizedCars.length,

      totalEmployees:
        employeeCount,

      passengerCount:
        car.passengers.length,

      /*
        Пассажиры уже идут в порядке:

        работа → первый → второй → третий → последний
      */
      passengers:
        car.passengers,

      routeDistanceMeters:
        Math.round(
          car.distanceMeters
        ),

      routeDistanceKm:
        Number(
          (
            car.distanceMeters / 1000
          ).toFixed(2)
        ),

      totalOptimizedDistanceMeters:
        Math.round(
          totalOptimizedDistance
        ),

      totalOptimizedDistanceKm:
        Number(
          (
            totalOptimizedDistance / 1000
          ).toFixed(2)
        ),

      optimizationMethod:
        optimization.method,

      exactOptimization:
        employeeCount <=
          EXACT_OPTIMIZATION_LIMIT,

      maxPassengers,

      settings
    }
  })
);
